import React, { useEffect, useRef } from 'react';
import { WEDDING } from '../weddingData';
import './Hero.css';

function useCountdown(targetDate) {
  const [timeLeft, setTimeLeft] = React.useState({});
  React.useEffect(() => {
    const calc = () => {
      const diff = +new Date(targetDate) - +new Date();
      if (diff <= 0) return setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      setTimeLeft({
        days: Math.floor(diff / 86400000),
        hours: Math.floor((diff / 3600000) % 24),
        minutes: Math.floor((diff / 60000) % 60),
        seconds: Math.floor((diff / 1000) % 60),
      });
    };
    calc();
    const t = setInterval(calc, 1000);
    return () => clearInterval(t);
  }, [targetDate]);
  return timeLeft;
}

export default function Hero() {
  const canvasRef = useRef(null);
  const timeLeft = useCountdown(WEDDING.date);

  // Animated particle starfield
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    let animId;

    const resize = () => {
      canvas.width = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
    };
    resize();
    window.addEventListener('resize', resize);

    const stars = Array.from({ length: 180 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      r: Math.random() * 1.8 + 0.3,
      alpha: Math.random(),
      speed: Math.random() * 0.004 + 0.001,
    }));

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      stars.forEach((s) => {
        s.alpha += s.speed;
        if (s.alpha > 1 || s.alpha < 0) s.speed *= -1;
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(232, 213, 163, ${s.alpha})`;
        ctx.fill();
      });
      animId = requestAnimationFrame(draw);
    };
    draw();

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', resize);
    };
  }, []);

  return (
    <header id="hero" className="hero-section">
      <canvas ref={canvasRef} className="hero-starfield" />
      <div className="hero-overlay" />

      <div className="hero-content">
        <div className="hero-eyebrow">
          <span className="eyebrow-line" />
          <span className="eyebrow-text">You Are Invited</span>
          <span className="eyebrow-line" />
        </div>

        <h1 className="hero-title">
          <span className="hero-name-groom">{WEDDING.groomName}</span>
          <span className="hero-and">&amp;</span>
          <span className="hero-name-bride">{WEDDING.brideName}</span>
        </h1>

        <p className="hero-ceremony-info">
          {WEDDING.date.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
          &nbsp;&mdash;&nbsp;{WEDDING.venue}
        </p>

        <div className="countdown-container">
          {[['days', timeLeft.days], ['hours', timeLeft.hours], ['minutes', timeLeft.minutes], ['seconds', timeLeft.seconds]].map(([label, val]) => (
            <div className="countdown-box" key={label}>
              <span className="countdown-value">{String(val ?? 0).padStart(2, '0')}</span>
              <span className="countdown-label">{label}</span>
            </div>
          ))}
        </div>

        <div className="hero-actions">
          <button
            className="hero-btn hero-btn--primary"
            onClick={() => document.getElementById('rsvp')?.scrollIntoView({ behavior: 'smooth' })}
          >
            RSVP Now
          </button>
          <button
            className="hero-btn hero-btn--ghost"
            onClick={() => document.getElementById('story')?.scrollIntoView({ behavior: 'smooth' })}
          >
            Our Story ↓
          </button>
        </div>
      </div>

      <div className="hero-scroll-hint">
        <span className="scroll-line" />
        <span className="scroll-text">Scroll</span>
      </div>
    </header>
  );
}
